module synchronizer(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input data_in,
    input data_en,
    output dataout
);
// YOUR CODE HERE
reg [3:0] data_reg;
reg [3:0] en_data_reg;
reg en_clap_one;
reg en_clap_two;
//data_reg
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) data_reg <= 4'd0;
    else data_reg <= data_in;
end
//en_data_reg
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) en_data_reg <= 4'd0;
    else en_data_reg <= data_en;
end
//en_clap_one
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) en_clap_one <= 4'd0;
    else en_clap_one <= en_data_reg;
end
//en_clap_two
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) en_clap_two <= 4'd0;
    else en_clap_two <= en_clap_one;
end
//dataout
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) dataout <= 4'd0;
    else if (en_clap_two) dataout <= data_reg;
    else dataout <= dataout;
end
endmodule
